import{c as s,a7 as t,y as o,B as i,v as e,D as a}from"./chunks/framework.3cjvm90C.js";const _=JSON.parse('{"title":"过程奖励模型（Process Reward Model）","description":"介绍过程奖励模型的原理及其在数学推理验证中的应用","frontmatter":{"title":"过程奖励模型（Process Reward Model）","description":"介绍过程奖励模型的原理及其在数学推理验证中的应用"},"headers":[],"relativePath":"rlhf/paper/prm.md","filePath":"rlhf/paper/prm.md","lastUpdated":1782448598000}'),n={name:"rlhf/paper/prm.md"};function l(p,r,h,d,c,m){return t(),o("div",null,[...r[0]||(r[0]=[i('<h1 id="过程奖励模型-process-reward-model" tabindex="-1">过程奖励模型（Process Reward Model） <a class="header-anchor" href="#过程奖励模型-process-reward-model" aria-label="Permalink to “过程奖励模型（Process Reward Model）”">​</a></h1><h2 id="过程监督-process-supervision" tabindex="-1">过程监督 (Process Supervision) <a class="header-anchor" href="#过程监督-process-supervision" aria-label="Permalink to “过程监督 (Process Supervision)”">​</a></h2><p>思维链采用逐步推理的方式得到最终结果，如果模型在某一步出现幻想 (Hallucination)，则差之毫厘，谬以千里，后面的错误会被放大，导致错误结果。</p><p>OpenAI 最近提出使用过程监督 (Process Supervision) 减少大模型幻想并提升大模型的数学推理能力，所以什么是过程监督？</p><p>过程监督 (Process Supervision) 是相对于之前的结果监督 (Outcome Supervison) 而言。众所周知，大模型基于人工反馈的强化学习部分需要用到奖励模型 (Reward Model, RM)，数学推理能力是基于思维链 (Chain of Thought)。传统的奖励模型采用的是结果监督的方式，仅使用思维链的最终结果进行判别与反馈，而过程监督则是对思维链的每步推理都进行反馈。因此，过程监督是针对思维链和奖励模型的一种改进方案。</p><h2 id="过程监督的动机" tabindex="-1">过程监督的动机 <a class="header-anchor" href="#过程监督的动机" aria-label="Permalink to “过程监督的动机”">​</a></h2><p>过程监督可以精确地指出发生错误的位置并提供反馈。还有个优势是可解释的对齐 (Alignment)，更容易训练出人类背书的模型。已有研究发现，在逻辑推理领域，使用结果监督的方式，存在“歪打正着”的现象，即模型会用一个错误推理得到正确的结果。显然这种情况可以通过过程监督的方式解决。</p><p>还有一点值得提到的是对齐税 (Alignment Tax)，即对齐后的模型在下游任务上可能会有性能损失。从实验结果来看，过程监督不仅没有负面效应，反而对模型性能有促进作用 (至少在数学领域如此)。</p><h2 id="数据采集" tabindex="-1">数据采集 <a class="header-anchor" href="#数据采集" aria-label="Permalink to “数据采集”">​</a></h2><p>显然，过程监督最大的阻碍是没有数据。之前的数据集都缺少逐步标注对错的结果，因此设计了一个标注 UI：</p><p><img src="https://coriva.eu.org/images/nlp/prmlabeling.png" alt="img"></p><p>所有结果都由大规模 generator 生成，每步的标注结果分三类： positive, negative 和 neutral：</p><blockquote><p>A positive label indicates that the step is correct and reasonable. A negative label indicates that the step is either incorrect or unreasonable. A neutral label indicates ambiguity. In practice, a step may be labelled neutral if it is subtly misleading, or if it is a poor suggestion that is technically still valid.</p></blockquote><p>neutral 标签的目的在于可在推理阶段灵活处理模糊结果，可正可负。</p><p>这个数据集叫做 PRM800K，包括 12K 个问题， 75K 个解答和 800K 个步骤的标注。</p><h3 id="采集策略" tabindex="-1">采集策略 <a class="header-anchor" href="#采集策略" aria-label="Permalink to “采集策略”">​</a></h3><p>最简单的策略是随机选择 generator 生成的解答。但这么做的最大问题在于如果所选的解答有明显错误，那么人工标注的意义就不大了。因此，作者们倾向于选择一些更难的例子，也就是更容易骗过奖励模型的例子。这个策略在传统机器学习中也非常常见，比如分类问题，选择更难分类的数据从而让模型更加健壮。</p><p>具体来说，作者们倾向于选择“看起来对但最终答案错误”的解答 (convincing wrong-answer)。<code>convincing</code>表示目前最优的奖励模型 (Process-supervised Reward Model, PRM) 对其打分较高，<code>wrong-answer</code>代表它的最终答案错误。期待用这样的策略可以获取更多的信息：保证当前的 PRM 至少有一处对该解答判断有误。</p><p>此外， PRM 还在数据采集的过程中不断迭代，对每个问题都生成 N 个结果，选择 PRM 打分前 K 个进行标注。</p><h2 id="结果奖励模型-orm" tabindex="-1">结果奖励模型(ORM) <a class="header-anchor" href="#结果奖励模型-orm" aria-label="Permalink to “结果奖励模型(ORM)”">​</a></h2><p>用如下方式对 ORM 进行训练：对每个问题，随机采样 generator 生成的固定数目的解答，并训练 ORM 预测每个解答是否正确。实践中的判断可以自动完成，用最后一个 token 评判对错。推理时，用 ORM 对最后一个 token 的预测作为总得分。</p><p>但这种自动评价方式有一些瑕疵：步骤出错但结果正确的解答可能会被误判。</p><h2 id="过程奖励模型-prm" tabindex="-1">过程奖励模型（PRM） <a class="header-anchor" href="#过程奖励模型-prm" aria-label="Permalink to “过程奖励模型（PRM）”">​</a></h2><p>过程奖励模型 PRM （Process Reward Model）可以对推理过程中的每个推理步骤进行评分，逐步评估推理路径，识别可能出现的任何错误的特定位置来提供精确的反馈，这是强化学习和自动校正中有价值的信号。</p><p><img src="https://openreasoner.github.io/assets/images/mdp.png" alt="MDP"></p><h2 id="过程奖励模型原理" tabindex="-1">过程奖励模型原理 <a class="header-anchor" href="#过程奖励模型原理" aria-label="Permalink to “过程奖励模型原理”">​</a></h2><h4 id="orm-目标函数" tabindex="-1">ORM 目标函数 <a class="header-anchor" href="#orm-目标函数" aria-label="Permalink to “ORM 目标函数”">​</a></h4>',27),e("p",null,[a("对于 ORM，给定一个数学问题 q 和其解 s， ORM （Q ×S →ℝ ）为 s 分配一个单一实数值，已表明 s 是否正确。ORM 通常使用交叉熵损失进行训练： $$ {\\mathcal L}"),e("em",{s:""},"{ORM} = y"),a(" log r_{s} + (1-y_{s})log(1-r_{s}) $$ 中 ys 是标签，表示 s 是否正确， rs 是 ORM 模型分配给 s 的 sigmoid 分数。")],-1),e("h3",{id:"prm-目标函数",tabindex:"-1"},[a("PRM 目标函数 "),e("a",{class:"header-anchor",href:"#prm-目标函数","aria-label":"Permalink to “PRM 目标函数”"},"​")],-1),e("p",null,"过程奖励模型的核心思想是通过步骤级别的标注数据集，训练过程奖励模型来预测解决方案中每个中间步骤的正确性，基本原理如下： $$ r_{s_i}=PRM([q,s_{1:i-1}], s_i) $$ 其中 $s_{1:i}=[s_1,...,s_i]$ 表解决方案 $s$ 中的第 $s_i$ 个步骤，这提供了比 ORM 更精确和更细粒度的反馈，因为它识别了错误的确切位置。",-1),e("p",null,"给定一个数学问题 $q$ 和对应的解决方案 $s$， PRM 为 $s$ 的每个推理步骤 $s_i$ 分配一个分数，通常使用以下方式进行训练：",-1),e("p",null,[a("$$ {\\mathcal L}"),e("em",{i:"1"},"{PRM} = \\sum\\limits"),a("\\limits^{K} y_{s_i} log r_{s_i} + (1-y_{s_i})log(1-r_{s_i}) $$")],-1),i('<p>其中 $y_{s_i}$ 是步骤 $s_{i}$ 的标签，表示步骤 $s_{i}$ 是否正确；$r_{s_{i} }$ 是 PRM 为步骤 $s_{i}$ 的分配的 sigmoid 分数，$K$ 表示 $s$ 包含的推理步骤数。</p><h2 id="prm-的训练" tabindex="-1">PRM 的训练 <a class="header-anchor" href="#prm-的训练" aria-label="Permalink to “PRM 的训练”">​</a></h2><p>PRM 的训练有更多细节：训练 PRM 对每一步推理的最后一个 token 进行评判。让 PRM 对整个解答的每一步都进行预测，下图中是 PRM 对同一问题的两个不同解答的打分可视化，绿色代表 PRM 打出高分，红色代表低分(有错)：</p><p><img src="https://coriva.eu.org/images/nlp/prmdemo.png" alt="img"></p><p>为了对不同解答进行比较，需要对每个解答统一打分，做法是将每步的正确概率相乘。</p><p>训练 PRM 时，遇到每一个出错步时就停止。这么做的目的是让过程监督和结果监督的方案更可比：对于正确解答，两种方案对模型提供了同样的信息，每步都是正确的；对错误解答，两种方案都犯了至少一个错误，但过程监督额外提供了错误发生的位置信息。</p><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to “总结”">​</a></h2><p>奖励模型在 RLHF 过程中扮演举足轻重的作用，它的好坏直接影响模型的最终性能。</p><h2 id="参考文献" tabindex="-1">参考文献 <a class="header-anchor" href="#参考文献" aria-label="Permalink to “参考文献”">​</a></h2><p><a href="https://arxiv.org/abs/2312.08935" target="_blank" rel="noreferrer">[1] Wang P, Li L, Shao Z, et al. Math-shepherd: Verify and reinforce llms step-by-step without human annotations[C]//Proceedings of the 62nd Annual Meeting of the Association for Computational Linguistics (Volume 1: Long Papers). 2024: 9426-9439.</a></p><p><a href="https://arxiv.org/pdf/2410.09671" target="_blank" rel="noreferrer">[2] Wang J, Fang M, Wan Z, et al. OpenR: An Open Source Framework for Advanced Reasoning with Large Language Models[J]. arXiv preprint arXiv:2410.09671, 2024.</a></p><p>[3]<em><a href="https://arxiv.org/abs/2305.20050" target="_blank" rel="noreferrer">Let ’s Verify Step by Step</a></em>: a good introduction to PRMs.</p><p>[4]<em><a href="https://arxiv.org/abs/2211.14275" target="_blank" rel="noreferrer">Solving math word problems with process- and outcome-based feedback</a></em>: the canonical citation in all PRM and reasoning works in 2023.</p><p>[5]<em><a href="https://arxiv.org/abs/2308.01825" target="_blank" rel="noreferrer">Scaling Relationship on Learning Mathematical Reasoning with Large Language Models</a></em>: A paper that studies the method of rejection sampling for reasoning problems, among other contributions.</p><p>[6]<em><a href="https://arxiv.org/abs/2310.10080" target="_blank" rel="noreferrer">Let&#39;s reward step by step: Step-Level reward model as the Navigators for Reasoning</a></em></p>',15)])])}const b=s(n,[["render",l]]);export{_ as __pageData,b as default};
